function autoFormatTime(u){let E=u['value']['replace'](/\D/g,'');switch(E['length']>0x4&&(E=E['slice'](0x0,0x4)),E['length']){case 0x0:case 0x1:case 0x2:u['value']=E;break;case 0x3:if(parseInt(E['slice'](0x0,0x2),0xa)<=0x17)u['value']=E['slice'](0x0,0x2)+':'+E['slice'](0x2);else{let F=E['slice'](0x0,0x1)['padStart'](0x2,'0'),q=E['slice'](0x1);u['value']=F+':'+q;}break;case 0x4:let J=E['slice'](0x0,0x2),Y=E['slice'](0x2);u['value']=J+':'+Y;}}function transformTimeValue(u){let E=u['trim']();if(/^\d{2}$/['test'](E))return E[0x0]['padStart'](0x2,'0')+':'+E[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](E))return 0x3===E['length']?parseInt(E['slice'](0x0,0x2),0xa)<=0x17?E['slice'](0x0,0x2)+':'+E['slice'](0x2):E['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+E['slice'](0x1):E['slice'](0x0,0x2)+':'+E['slice'](0x2);if(E['includes'](':')){let [J,Y]=E['split'](':');return Y||(Y='00'),J=J['padStart'](0x2,'0'),Y=Y['padStart'](0x2,'0'),J+':'+Y;}return E;}